        assert_eq!(
            payload.reserve.bridge.bindings()[0].type_spelling,
            "OuterTwoEdgeModeEquality"
        );
        assert_eq!(payload.left_lookup_ordinal, 1);
        assert_eq!(payload.right_lookup_ordinal, 2);

