            corruptions.push(invalid);
            let mut invalid = exact_output();
            invalid.asserted_type_input.head = invalid.subject_result_input.head.clone();
            corruptions.push(invalid);
            let mut invalid = exact_output();
            invalid.asserted_type_input.site = invalid.subject_result_input.site.clone();
            corruptions.push(invalid);
            let mut invalid = exact_output();
