            corruptions.push(invalid);
            let mut invalid = exact_output();
            invalid.payload.subject_lookup_ordinal = 2;
            corruptions.push(invalid);
            let mut invalid = exact_output();
            invalid.subject_result_input.spelling = OUTER.to_owned();
